from collections import Counter

def is_palindrome(num: int) -> bool:
    return str(num) == str(num)[::-1]

def is_special(num: int) -> bool:
    s = str(num)
    count = Counter(s)
    for k, v in count.items():
        if int(k) != v:
            return False
    return True

def solve(n: int) -> int:
    if n == 0:
        return 1

    # Check numbers starting from n + 1
    current = n + 1
    while True:
        if is_palindrome(current) and is_special(current):
            return current
        current += 1
